import React from 'react';
import { useEventCallback } from '.';

export function useDelayCallback<T extends (...args: never[]) => unknown>(
  callback: T,
): [callbackWithDelay: (args: Parameters<T>, timeout: number) => void, cleanup: () => void] {
  const delayTimerID = React.useRef<number>();
  const cleanup = useEventCallback(() => {
    if (delayTimerID.current !== undefined) {
      window.clearTimeout(delayTimerID.current);
      delayTimerID.current = undefined;
    }
  });
  const callbackWithDelay = useEventCallback((args: Parameters<T>, timeout: number) => {
    cleanup();
    // console.log('callbackWithDelay', args, timeout);
    // if (timeout === 0) {
    //   callback(...args);
    //   return;
    // }
    delayTimerID.current = window.setTimeout(() => {
      // console.trace('callbackWithDelay execute', args, timeout);
      callback(...args);
    }, timeout);
  });
  return [callbackWithDelay, cleanup];
}
